using System.Collections;
using System.Text;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Mapa-Múndi (GDD "HUD" / "Painel Automático de Área" / "Apresentação do
/// Mundo"): toda a interface do Mapa-Múndi — HUD do Coração de Gaia (Runas de
/// Gaia + emblemas dos 6 mundos), HUD dentro de um mundo (nome + emblema do
/// mundo, se já obtido), apresentação de mundo (logo/música/frase, mostrada
/// uma única vez por mundo), painel automático de área (bloqueada/Vila/Boss/
/// desbloqueada, com custo, "Desbloquear"/"Viajar" e contadores "X/Y" ou
/// "X/?") e a legenda de comandos no rodapé.
///
/// Chamado por <see cref="WorldMapController"/> — todos os textos/formatos são
/// configuráveis no Inspector.
/// </summary>
public class WorldMapUI : MonoBehaviour
{
    [Header("HUD — Coração de Gaia")]
    [Tooltip("Raiz do HUD mostrado quando a bola está no Coração de Gaia (Runas de Gaia + emblemas dos 6 mundos).")]
    public GameObject gaiaHubHudRoot;

    [Tooltip("Lista dos 6 mundos: logo (WorldData.mapLogo), estado de \"já visitado\" (ícone normal vs. silhueta) e emblema do mundo (mostrado se já obtido).")]
    public WorldEmblemSlot[] worldEmblemSlots;

    [Header("HUD — Dentro de um Mundo")]
    [Tooltip("Raiz do HUD mostrado sempre que a bola está fora do Coração de Gaia (nome do mundo + emblema, se obtido).")]
    public GameObject worldHudRoot;

    public TMP_Text worldNameText;

    [Tooltip("Imagem do emblema do mundo (WorldData.worldEmblem.icon) — só fica visível depois de obtido (GameVariables, emblem.obtainedVariable).")]
    public Image worldEmblemImage;

    [Tooltip("Contentor do emblema do mundo (activado/desactivado consoante o emblema já tenha sido obtido).")]
    public GameObject worldEmblemContainer;

    [Header("HUD — Recursos (Comum)")]
    public TMP_Text runasDeGaiaText;
    public string runasDeGaiaFormat = "{0}";

    [Header("Apresentação do Mundo (1ª vez)")]
    [Tooltip("Raiz do painel de apresentação em ecrã cheio — logo, nome e frase temática do mundo, mostrado apenas na primeira vez que o jogador chega à 1ª área de cada mundo.")]
    public GameObject presentationRoot;

    [Tooltip("CanvasGroup de 'presentationRoot', usado para o fade de entrada/saída.")]
    public CanvasGroup presentationCanvasGroup;

    public Image presentationLogoImage;
    public TMP_Text presentationWorldNameText;
    public TMP_Text presentationThemePhraseText;

    [Tooltip("Duração (segundos) do fade-in/fade-out da apresentação do mundo.")]
    public float presentationFadeDuration = 0.5f;

    [Tooltip("Tempo (segundos) que a apresentação fica visível antes de desaparecer automaticamente.")]
    public float presentationHoldDuration = 4f;

    [Header("Painel Automático de Área")]
    [Tooltip("Raiz do painel automático — aparece sempre que a bola pára num nó que não seja o Coração de Gaia.")]
    public GameObject panelRoot;

    [Tooltip("Nome da área (ou \"?????????????\"/\"????????\" enquanto oculto).")]
    public TMP_Text panelNameText;

    [Tooltip("Custo de desbloqueio (\"Custo: X Runas de Gaia\") — visível apenas em áreas Normais bloqueadas mas alcançáveis.")]
    public TMP_Text panelCostText;

    [Tooltip("Acção disponível: \"A: Desbloquear\" ou \"A: Viajar\". Fica oculto para áreas de Boss ainda não desbloqueadas (não compráveis).")]
    public TMP_Text panelActionText;

    [Tooltip("Contentor dos contadores da área (Runas/NPCs/Sussurros/Baús/Fragmentos) — só visível em áreas desbloqueadas (ou Boss já descoberto).")]
    public GameObject panelStatsRoot;

    public TMP_Text panelStatsText;

    [Header("Painel — Textos")]
    public string lockedNamePlaceholder = "?????????????";
    public string bossNamePlaceholder = "????????";
    public string costFormat = "Custo: {0} Runas de Gaia";
    public string actionUnlockText = "A: Desbloquear";
    public string actionTravelText = "A: Viajar";

    [Tooltip("Formato de cada linha de contador. {0} = nome do contador, {1} = encontrados, {2} = total (ou \"?\" se ainda não revelado).")]
    public string statLineFormat = "{0}: {1}/{2}";
    public string statRunasLabel = "Runas de Gaia";
    public string statNpcsLabel = "NPCs";
    public string statWhispersLabel = "Sussurros";
    public string statChestsLabel = "Baús";
    public string statFragmentsLabel = "Fragmentos Vitais";
    public string hiddenTotalSymbol = "?";

    [Header("Legenda de Comandos (Rodapé)")]
    public GameObject legendRoot;
    public TMP_Text legendText;

    [TextArea]
    [Tooltip("Legenda mostrada normalmente: navegação (analógico esquerdo) + confirmar/voltar.")]
    public string legendDefault = "Mover: Analógico Esquerdo   •   A: Confirmar   •   B: Voltar";

    [TextArea]
    [Tooltip("Legenda mostrada quando o jogador tem a Visão do Mapa-Múndi (acrescenta o analógico direito).")]
    public string legendWithMapVision = "Mover: Analógico Esquerdo   •   A: Confirmar   •   B: Voltar   •   Analógico Direito: Visão do Mapa-Múndi";

    private Coroutine presentationRoutine;

    // ==================================================================
    // Ciclo de Vida
    // ==================================================================

    private void OnEnable()
    {
        var pp = PlayerProgress.Instance;
        if (pp != null) pp.RunasChanged += HandleRunasChanged;

        RefreshRunasDeGaia();
        HidePanel();
        if (presentationRoot != null) presentationRoot.SetActive(false);
    }

    private void OnDisable()
    {
        var pp = PlayerProgress.Instance;
        if (pp != null) pp.RunasChanged -= HandleRunasChanged;
    }

    private void HandleRunasChanged(int current, int total) => RefreshRunasDeGaia();

    private void RefreshRunasDeGaia()
    {
        if (runasDeGaiaText == null) return;

        int amount = PlayerProgress.Instance != null ? PlayerProgress.Instance.GetResourceAmount(PlayerResourceType.RunasDeGaia) : 0;
        runasDeGaiaText.text = string.Format(runasDeGaiaFormat, amount);
    }

    // ==================================================================
    // HUD — Coração de Gaia
    // ==================================================================

    /// <summary>Mostra o HUD do Coração de Gaia (Runas de Gaia + emblemas dos 6 mundos) e esconde o HUD/painel de mundo.</summary>
    public void ShowGaiaHubHud(WorldMapController controller)
    {
        HidePanel();

        if (gaiaHubHudRoot != null) gaiaHubHudRoot.SetActive(true);
        if (worldHudRoot != null) worldHudRoot.SetActive(false);

        RefreshRunasDeGaia();
        RefreshWorldEmblemSlots();
        RefreshLegend(controller);
    }

    private void RefreshWorldEmblemSlots()
    {
        if (worldEmblemSlots == null) return;

        var pp = PlayerProgress.Instance;

        foreach (var slot in worldEmblemSlots)
        {
            if (slot == null || slot.world == null) continue;

            bool visited = slot.entryArea == null || pp == null || pp.HasVisited(slot.entryArea);

            if (slot.logoImage != null)
            {
                slot.logoImage.sprite = slot.world.mapLogo;
                slot.logoImage.enabled = slot.world.mapLogo != null;
            }

            if (slot.unvisitedOverlay != null)
                slot.unvisitedOverlay.SetActive(!visited);

            if (slot.emblemImage != null)
            {
                bool hasEmblem = IsEmblemObtained(slot.world.worldEmblem);
                slot.emblemImage.enabled = hasEmblem && slot.world.worldEmblem != null && slot.world.worldEmblem.icon != null;
                if (slot.emblemImage.enabled) slot.emblemImage.sprite = slot.world.worldEmblem.icon;
            }
        }
    }

    // ==================================================================
    // HUD — Dentro de um Mundo
    // ==================================================================

    /// <summary>Mostra o HUD de mundo (nome + emblema, se já obtido) e esconde o HUD do Coração de Gaia.</summary>
    public void ShowWorldHud(WorldData world)
    {
        if (gaiaHubHudRoot != null) gaiaHubHudRoot.SetActive(false);
        if (worldHudRoot != null) worldHudRoot.SetActive(true);

        if (worldNameText != null) worldNameText.text = world != null ? world.mapWorldName : "";

        bool hasEmblem = world != null && IsEmblemObtained(world.worldEmblem) && world.worldEmblem.icon != null;

        if (worldEmblemContainer != null) worldEmblemContainer.SetActive(hasEmblem);
        if (worldEmblemImage != null)
        {
            worldEmblemImage.enabled = hasEmblem;
            if (hasEmblem) worldEmblemImage.sprite = world.worldEmblem.icon;
        }

        RefreshRunasDeGaia();
        RefreshLegend(WorldMapController.Instance);
    }

    private static bool IsEmblemObtained(EmblemData emblem)
    {
        if (emblem == null || string.IsNullOrEmpty(emblem.obtainedVariable)) return false;
        var vars = GameVariables.Instance;
        return vars != null && vars.GetBool(emblem.obtainedVariable);
    }

    // ==================================================================
    // Apresentação do Mundo (1ª vez)
    // ==================================================================

    /// <summary>
    /// Mostra, em ecrã cheio, o logo/nome/frase temática de "world" (GDD:
    /// apenas na primeira vez que o jogador chega à 1ª área desse mundo).
    /// Toca 'world.presentationMusic' (se definido) e bloqueia os controlos do
    /// Mapa-Múndi enquanto estiver visível.
    /// </summary>
    public void ShowWorldPresentation(WorldData world)
    {
        if (world == null || presentationRoot == null) return;

        if (presentationRoutine != null) StopCoroutine(presentationRoutine);
        presentationRoutine = StartCoroutine(PresentationRoutine(world));
    }

    private IEnumerator PresentationRoutine(WorldData world)
    {
        var controller = WorldMapController.Instance;
        controller?.SetControlsLocked(true);

        if (presentationLogoImage != null)
        {
            presentationLogoImage.sprite = world.mapLogo;
            presentationLogoImage.enabled = world.mapLogo != null;
        }

        if (presentationWorldNameText != null)
            presentationWorldNameText.text = world.mapWorldName;

        if (presentationThemePhraseText != null)
        {
            bool hasPhrase = !string.IsNullOrEmpty(world.themePhrase);
            presentationThemePhraseText.gameObject.SetActive(hasPhrase);
            presentationThemePhraseText.text = world.themePhrase;
        }

        if (world.presentationMusic != null && AudioManager.Instance != null)
            AudioManager.Instance.PlaySE(world.presentationMusic);

        presentationRoot.SetActive(true);
        yield return Fade(presentationCanvasGroup, 0f, 1f, presentationFadeDuration);

        yield return new WaitForSeconds(Mathf.Max(0f, presentationHoldDuration));

        yield return Fade(presentationCanvasGroup, 1f, 0f, presentationFadeDuration);
        presentationRoot.SetActive(false);

        controller?.SetControlsLocked(false);
        presentationRoutine = null;
    }

    private static IEnumerator Fade(CanvasGroup group, float from, float to, float duration)
    {
        if (group == null) yield break;

        if (duration <= 0f) { group.alpha = to; yield break; }

        float elapsed = 0f;
        group.alpha = from;

        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            group.alpha = Mathf.Lerp(from, to, Mathf.Clamp01(elapsed / duration));
            yield return null;
        }

        group.alpha = to;
    }

    // ==================================================================
    // Painel Automático de Área
    // ==================================================================

    /// <summary>Esconde o painel automático de área (Coração de Gaia, ou enquanto a bola viaja).</summary>
    public void HidePanel()
    {
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    /// <summary>Re-mostra o painel para o nó actual (ex: depois de desbloquear uma área, para reflectir o novo estado).</summary>
    public void RefreshPanel()
    {
        var node = WorldMapController.Instance != null ? WorldMapController.Instance.CurrentNode : null;
        if (node != null) ShowPanelForNode(node);
    }

    /// <summary>
    /// Mostra o painel automático para "node" (GDD "Painel Automático de
    /// Área"): bloqueada mostra "?????????????" + custo + "Desbloquear";
    /// desbloqueada mostra o nome real + "Viajar" + contadores; Vilas têm
    /// custo 0 e desbloqueiam automaticamente; áreas de Boss mostram
    /// "????????" até serem descobertas e nunca são compráveis. Não faz nada
    /// para o Coração de Gaia.
    /// </summary>
    public void ShowPanelForNode(WorldMapNode node)
    {
        if (node == null || node.isGaiaHub || node.area == null)
        {
            HidePanel();
            return;
        }

        if (panelRoot != null) panelRoot.SetActive(true);

        var area = node.area;
        var pp = PlayerProgress.Instance;

        bool unlocked = node.IsUnlocked;
        bool isBoss = area.mapNodeType == AreaData.MapNodeType.Boss;
        bool isVila = area.mapNodeType == AreaData.MapNodeType.Vila;
        bool bossDiscovered = isBoss && pp != null && pp.HasDiscoveredBoss(area.world);

        string displayName;
        if (isBoss) displayName = bossDiscovered ? area.bossDisplayName : bossNamePlaceholder;
        else if (!unlocked) displayName = lockedNamePlaceholder;
        else displayName = area.displayName;

        if (panelNameText != null) panelNameText.text = displayName;

        if (panelCostText != null)
        {
            bool showCost = !unlocked && !isVila && !isBoss;
            panelCostText.gameObject.SetActive(showCost);
            if (showCost) panelCostText.text = string.Format(costFormat, Mathf.Max(0, area.unlockCost));
        }

        if (panelActionText != null)
        {
            if (unlocked)
            {
                panelActionText.gameObject.SetActive(true);
                panelActionText.text = actionTravelText;
            }
            else if (isBoss)
            {
                // Áreas de Boss nunca são compráveis — desbloqueiam automaticamente.
                panelActionText.gameObject.SetActive(false);
            }
            else
            {
                panelActionText.gameObject.SetActive(true);
                panelActionText.text = actionUnlockText;
            }
        }

        RefreshPanelStats(area, unlocked, bossDiscovered);
    }

    private void RefreshPanelStats(AreaData area, bool unlocked, bool bossDiscovered)
    {
        if (panelStatsRoot == null) return;

        var pp = PlayerProgress.Instance;
        bool isBoss = area.mapNodeType == AreaData.MapNodeType.Boss;

        bool show = pp != null && unlocked && (!isBoss || bossDiscovered);
        panelStatsRoot.SetActive(show);
        if (!show) return;

        bool revealTotals = pp.AreWorldTotalsDiscovered(area.world)
                             || pp.HasDefeatedBoss(area.world)
                             || (WorldMapController.Instance != null
                                 && WorldMapController.Instance.mapVisionUpgrade != null
                                 && pp.HasUpgrade(WorldMapController.Instance.mapVisionUpgrade));

        var sb = new StringBuilder();

        AppendStatLine(sb, statRunasLabel, pp.GetRunasFound(area), area.totalRunas, revealTotals);
        AppendStatLine(sb, statNpcsLabel, pp.GetNpcsRescued(area), area.totalNpcsToRescue, revealTotals);
        AppendStatLine(sb, statWhispersLabel, pp.GetWhispersFound(area), area.totalWhispers, revealTotals);
        AppendStatLine(sb, statChestsLabel, pp.GetChestsFound(area), area.totalChests, revealTotals);
        AppendStatLine(sb, statFragmentsLabel, pp.GetFragmentsFound(area), area.totalFragments, revealTotals);

        if (panelStatsText != null) panelStatsText.text = sb.ToString().TrimEnd('\n');
        if (sb.Length == 0) panelStatsRoot.SetActive(false);
    }

    private void AppendStatLine(StringBuilder sb, string label, int found, int total, bool revealTotals)
    {
        if (total <= 0) return;

        string totalStr = revealTotals ? total.ToString() : hiddenTotalSymbol;
        sb.AppendLine(string.Format(statLineFormat, label, found, totalStr));
    }

    // ==================================================================
    // Legenda de Comandos
    // ==================================================================

    private void RefreshLegend(WorldMapController controller)
    {
        if (legendText == null) return;

        bool hasMapVision = controller != null
                            && controller.mapVisionUpgrade != null
                            && PlayerProgress.Instance != null
                            && PlayerProgress.Instance.HasUpgrade(controller.mapVisionUpgrade);

        legendText.text = hasMapVision ? legendWithMapVision : legendDefault;
        if (legendRoot != null) legendRoot.SetActive(true);
    }
}

/// <summary>
/// Mapa-Múndi (HUD do Coração de Gaia): associa um <see cref="WorldData"/> ao
/// seu logo, estado de "já visitado" e emblema (mostrado depois de obtido).
/// </summary>
[System.Serializable]
public class WorldEmblemSlot
{
    [Tooltip("Mundo representado por este slot.")]
    public WorldData world;

    [Tooltip("Imagem que mostra WorldData.mapLogo.")]
    public Image logoImage;

    [Tooltip("Objecto activado enquanto o jogador NUNCA tiver visitado a área de entrada deste mundo (ex: silhueta/sombra sobre o logo). Deixar vazio para mostrar sempre o logo normal.")]
    public GameObject unvisitedOverlay;

    [Tooltip("Área de entrada deste mundo (1ª área, ligada directamente ao Coração de Gaia) — usada apenas para determinar 'unvisitedOverlay' via PlayerProgress.HasVisited.")]
    public AreaData entryArea;

    [Tooltip("Imagem do emblema do mundo (WorldData.worldEmblem.icon) — fica visível apenas depois de obtido.")]
    public Image emblemImage;
}
